// PROBLEM: Race condition
class Counter {
    private int count = 0;

    // NOT thread-safe — two threads can read same value
    public void increment() {
        count++;  // Read → Modify → Write (3 steps, not atomic!)
    }
}

// SOLUTION 1: synchronized method
class SafeCounter {
    private int count = 0;

    public synchronized void increment() {
        count++;  // Only one thread at a time
    }

    public synchronized int getCount() {
        return count;
    }
}

// SOLUTION 2: synchronized block (finer control)
class BetterCounter {
    private int count = 0;
    private final Object lock = new Object();

    public void increment() {
        synchronized (lock) {
            count++;
        }
    }
}

// SOLUTION 3: AtomicInteger (best for counters)
import java.util.concurrent.atomic.AtomicInteger;

class BestCounter {
    private AtomicInteger count = new AtomicInteger(0);

    public void increment() {
        count.incrementAndGet();  // Thread-safe, no lock needed!
    }

    public int getCount() {
        return count.get();
    }
}

