// JVM MEMORY AREAS:
// 1. STACK — per thread, stores:
//    - Method call frames
//    - Local variables (primitives)
//    - References to objects on heap
//    - LIFO — last method called, first to return

// 2. HEAP — shared, stores:
//    - All objects (new keyword)
//    - Instance variables
//    - Arrays

// 3. Method Area — class metadata, static variables
// 4. String Pool — cached string literals

// Example: where does each go?
public void process() {
    int x = 10;                  // Stack — primitive
    String name = "Alice";       // Stack (reference) + String Pool (object)
    Employee emp = new Employee(); // Stack (reference) + Heap (object)
    List<String> list = new ArrayList<>(); // Stack (ref) + Heap (object)
}

// GARBAGE COLLECTION
// Young Gen: new objects, minor GC (fast, frequent)
// Old Gen: survived multiple GCs, major GC (slow, rare)
// GC Algorithms: Serial, Parallel, G1 (default Java 9+), ZGC

// OutOfMemoryError causes:
// 1. Memory leak — objects referenced but not used
// 2. Too large data structure
// 3. Heap too small — increase with -Xmx

// JVM arguments
// -Xms512m    — initial heap size
// -Xmx2g     — maximum heap size
// -XX:+UseG1GC — use G1 garbage collector

// Objects eligible for GC:
// 1. Nullified reference
Employee emp = new Employee();
emp = null;  // Previous object eligible for GC

// 2. Out of scope
public void method() {
    Employee local = new Employee();
}  // local goes out of scope — eligible

// 3. Island of isolation
class Node {
    Node next;
}
Node a = new Node();
Node b = new Node();
a.next = b;
b.next = a;
a = null;
b = null;
// Both eligible — circular reference but no external reference

// Memory leak patterns in Java:
// 1. Static collections that grow forever
static List<Object> cache = new ArrayList<>();  // Never cleared!

// 2. Listeners not removed
button.addActionListener(handler);
// If button removed but handler references large object — leak!

// 3. Inner class holds reference to outer class
class Outer {
    byte[] largeData = new byte[1000000];
    class Inner {  // Holds implicit reference to Outer!
        void process() {}
    }
}
// Fix: use static inner class
static class Inner { }  // No reference to Outer

// Request GC (not guaranteed)
System.gc();  // JVM may ignore this!

